previewCss:
.darma-loader-darma-custom-350 {color: var(--loader-color, #db2777);
  --loader-secondary-color: var(--loader-secondary-color, #f9a8d4);
  --loader-bg: var(--loader-bg, #ffffff);
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
}.darma-loader-darma-custom-350:before,.darma-loader-darma-custom-350:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #db2777) 0 60deg,var(--loader-secondary-color, #f9a8d4) 0 120deg);
  animation: darma-loader-darma-custom-350-l7 2s infinite alternate ease-in-out;
  rotate: 90deg;
}.darma-loader-darma-custom-350:before {translate: 0 -100%;
}.darma-loader-darma-custom-350:after {padding: 20%;
  mask: conic-gradient(from 120deg,#0000 120deg,currentColor 0) content-box exclude,conic-gradient(from 120deg,#0000 120deg,currentColor 0);
  animation-direction: alternate-reverse;
}@keyframes darma-loader-darma-custom-350-l7 {to{rotate: -90deg;
}}

